var superPow = function(a, b) {
    const MOD = 1337;
    const powMod = (base, exp) => {
        base %= MOD;
        let r = 1;
        while (exp > 0) {
            if (exp & 1) r = (r * base) % MOD;
            base = (base * base) % MOD;
            exp >>= 1;
        }
        return r;
    };
    let result = 1;
    let av = a % MOD;
    for (const d of b) {
        result = (powMod(result, 10) * powMod(av, d)) % MOD;
    }
    return result;
};
